def build_model(model_name, num_classes, pretrained_url=None, device="cpu"):
    if hasattr(models, model_name):
        model = getattr(models, model_name)(weights=None)
    else:
        raise ValueError(f"Unknown model: {model_name}")

    if pretrained_url:
        state = download_and_load_state_dict(pretrained_url, map_location=device)
